<?php require_once __DIR__.'/includes/functions.php';$spaces=db()->query("SELECT * FROM village_space_types WHERE active=1 ORDER BY sort_order,id")->fetchAll();if($_SERVER['REQUEST_METHOD']==='POST'){check_csrf();$ref=make_ref('FHBF-VIL');$is=(int)$_POST['is_member'];$amount=village_price($_POST['space_type'],$is);db()->prepare("INSERT INTO village_bookings(reference,applicant_name,business_name,email,phone,is_member,membership_number,space_type,amount_due,payment_reference,status) VALUES(?,?,?,?,?,?,?,?,?,?,'Submitted')")->execute([$ref,$_POST['applicant_name'],$_POST['business_name'],$_POST['email'],$_POST['phone'],$is,$_POST['membership_number']??'',$_POST['space_type'],$amount,$_POST['payment_reference']??'']);flash('success',"Booking received. Reference: $ref. Amount due: US$$amount");redirect('/village.php');}include __DIR__.'/includes/header.php';$items=db()->query("SELECT * FROM village_layout_items WHERE is_public=1 ORDER BY z_index,id")->fetchAll();?><section class="section"><h1>Business Village</h1><table><tr><th>Space</th><th>Member</th><th>Non-member</th></tr><?php foreach($spaces as $s): ?><tr><td><?=h($s['name'])?></td><td>US$<?=h($s['price_member'])?></td><td>US$<?=h($s['price_non_member'])?></td></tr><?php endforeach; ?></table><h2>Layout Preview</h2><div class="canvas" style="height:520px"><?php foreach($items as $it): ?><div class="item <?=h($it['item_type'])?>" style="left:<?=h($it['x_pos'])?>px;top:<?=h($it['y_pos'])?>px;width:<?=h($it['width'])?>px;height:<?=h($it['height'])?>px;z-index:<?=h($it['z_index'])?>"><?=h($it['label'])?></div><?php endforeach; ?></div><form class="card form" method="post"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><h2>Book Space</h2><label>Applicant Name<input name="applicant_name" required></label><label>Business Name<input name="business_name" required></label><label>Email<input name="email"></label><label>Phone<input name="phone" required></label><label>Are you member?<select name="is_member"><option value="1">Yes</option><option value="0">No</option></select></label><label>Membership No<input name="membership_number"></label><label>Space Type<select name="space_type"><?php foreach($spaces as $s): ?><option data-member="<?=h($s['price_member'])?>" data-nonmember="<?=h($s['price_non_member'])?>"><?=h($s['name'])?></option><?php endforeach; ?></select></label><label>Amount<input id="amount_due" readonly></label><label>Payment Reference<input name="payment_reference"></label><button>Submit Booking</button></form></section><?php include __DIR__.'/includes/footer.php'; ?>